   641→  // Get review state info
   642→  const { emoji, label } = getReviewStateInfo(review.state);
   643→
   644→  // Build task description
   645→  const reviewBody = review.body ? `\n\nReview Comment:\n${review.body}` : "";
   646→  const suggestions =
   647→    review.state === "approved"
   648→      ? "💡 Suggested: Merge the PR or wait for additional reviews"
   649→      : review.state === "changes_requested"
   650→        ? "💡 Suggested: Address the requested changes and update the PR"
   651→        : "💡 Suggested: Review the feedback and respond if needed";
   652→
   653→  const taskDescription = `${emoji} [GitHub PR #${pr.number} Review] ${label}\n\nPR: ${pr.title}\nReviewer: ${sender.login}\nRepo: ${repository.full_name}\nURL: ${review.html_url}${reviewBody}\n\n---\n${existingTask ? `Related task: ${existingTask.id}\n🔀 Consider routing to the same agent working on the related task.\n` : ""}${DELEGATION_INSTRUCTION}\n${suggestions}`;
   654→
   655→  // Create task (assigned to lead if available, otherwise unassigned)
   656→  const task = createTaskExtended(taskDescription, {
   657→    agentId: lead?.id ?? "",
   658→    source: "github",
   659→    vcsProvider: "github",
   660→    taskType: "github-review",
   661→    vcsRepo: repository.full_name,
   662→    vcsEventType: "pull_request_review",
   663→    vcsNumber: pr.number,
   664→    vcsAuthor: sender.login,
   665→    vcsUrl: review.html_url,
   666→  });
   667→
   668→  if (lead) {
   669→    console.log(
   670→      `[GitHub] Created task ${task.id} for PR #${pr.number} review (${review.state}) -> ${lead.name}`,
   671→    );
   672→  } else {
   673→    console.log(
   674→      `[GitHub] Created unassigned task ${task.id} for PR #${pr.number} review (${review.state}, no lead available)`,
   675→    );
   676→  }
   677→
   678→  // Add reaction to acknowledge the review
   679→  if (installation?.id) {
   680→    addIssueReaction(repository.full_name, pr.number, "eyes", installation.id);
   681→  }
   682→
   683→  return { created: true, taskId: task.id };
   684→}
   685→
   686→/**
   687→ * Get conclusion emoji and label for CI checks
   688→ */
   689→function getCheckConclusionInfo(conclusion: string | null): { emoji: string; label: string } {
   690→  switch (conclusion) {
   691→    case "success":
   692→      return { emoji: "✅", label: "PASSED" };
   693→    case "failure":
   694→      return { emoji: "❌", label: "FAILED" };
   695→    case "cancelled":
   696→      return { emoji: "⏹️", label: "CANCELLED" };
   697→    case "timed_out":
   698→      return { emoji: "⏱️", label: "TIMED OUT" };
   699→    case "action_required":
   700→      return { emoji: "⚠️", label: "ACTION REQUIRED" };
   701→    case "skipped":
   702→      return { emoji: "⏭️", label: "SKIPPED" };
   703→    case "neutral":
   704→      return { emoji: "➖", label: "NEUTRAL" };
   705→    default:
   706→      return { emoji: "❓", label: conclusion?.toUpperCase() ?? "UNKNOWN" };
   707→  }
   708→}
   709→
   710→/**
   711→ * Handle check_run events (CI check completed)
   712→ *
   713→ * This notifies agents when CI checks pass or fail on PRs they're working on.
   714→ */
   715→export async function handleCheckRun(
   716→  event: CheckRunEvent,
   717→): Promise<{ created: boolean; taskId?: string }> {
   718→  const { action, check_run, repository } = event;
   719→
   720→  // Only handle completed check runs
   721→  if (action !== "completed") {
   722→    return { created: false };
   723→  }
   724→
   725→  // Only notify on failure or action_required - success is less critical
   726→  // Skip neutral/skipped/cancelled as they're usually not actionable
   727→  const conclusion = check_run.conclusion;
   728→  if (conclusion !== "failure" && conclusion !== "action_required") {
   729→    return { created: false };
   730→  }
